#!/usr/bin/env python3
"""
Bug #2539: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['attention', 'cross_attention_fixed_kv'], ['broadcast', 'cumsum_last_axis'], ['layout', 'row_reduce_mul_transpose'], ['normalization', 'rmsnorm'], ['constant', 'cast_int_roundtrip'], ['fusion', 'matmul_add_biasgelu_bcast']]
Dependencies: numpy jax
Run         : python unique_2539.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 128])
_w4 = np.frombuffer(bytes.fromhex("f304b53d"), dtype=np.float32).reshape([1])
_w5 = np.frombuffer(bytes.fromhex("0200000000000000"), dtype=np.int64).reshape([1])
_w6 = np.frombuffer(bytes.fromhex("bd378635"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w8 = np.frombuffer(bytes.fromhex("0000c8c2"), dtype=np.float32).reshape([1])
_w9 = np.frombuffer(bytes.fromhex("0000c842"), dtype=np.float32).reshape([1])
_w10 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 128])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w12 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 128])
_w13 = np.frombuffer(bytes.fromhex("f304b53f"), dtype=np.float32).reshape([1])
_w14 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1])
_w15 = np.frombuffer(bytes.fromhex("0000003f"), dtype=np.float32).reshape([1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 128])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_cak_q = jnp.matmul(x, _w0)
    n0_cak_k = jnp.matmul(_w3, _w1)
    n0_cak_v = jnp.matmul(_w3, _w2)
    n0_cak_kt = jnp.transpose(n0_cak_k, [0, 2, 1])
    n0_cak_raw = jnp.matmul(n0_cak_q, n0_cak_kt)
    n0_cak_sc = n0_cak_raw * _w4
    n0_cak_sm = (lambda _x: _x / jnp.sum(_x, axis=-1, keepdims=True))(jnp.exp(n0_cak_sc - jnp.max(n0_cak_sc, axis=-1, keepdims=True)))
    n0_cak_out = jnp.matmul(n0_cak_sm, n0_cak_v)
    n100_cs_out = jnp.cumsum(n0_cak_out, axis=int(_w5.flat[0]))
    n200_rrmt_mean = jnp.mean(n100_cs_out, axis=(-1,), keepdims=True)
    n200_rrmt_sub = n100_cs_out - n200_rrmt_mean
    n200_rrmt_scl = n200_rrmt_sub * n200_rrmt_sub
    n200_rrmt_tp = jnp.transpose(n200_rrmt_scl, [0, 2, 1])
    n200_rrmt_out = jnp.transpose(n200_rrmt_tp, [0, 2, 1])
    n300_rms_sq = n200_rrmt_out * n200_rrmt_out
    n300_rms_mean = jnp.mean(n300_rms_sq, axis=(-1,), keepdims=True)
    n300_rms_add = n300_rms_mean + _w6
    n300_rms_sqrt = jnp.sqrt(n300_rms_add)
    n300_rms_sc = n200_rrmt_out / n300_rms_sqrt
    n300_rms_out = n300_rms_sc * _w7
    n400_cirt_cl = jnp.minimum(jnp.maximum(n300_rms_out, jnp.asarray(_w8, dtype=n300_rms_out.dtype)), jnp.asarray(_w9, dtype=jnp.maximum(n300_rms_out, jnp.asarray(_w8, dtype=n300_rms_out.dtype)).dtype))
    n400_cirt_i32 = n400_cirt_cl.astype(np.int32)
    n400_cirt_f32 = n400_cirt_i32.astype(np.float32)
    n400_cirt_out = n400_cirt_f32 * _w10
    n500_mabg_mm = jnp.matmul(n400_cirt_out, _w11)
    n500_mabg_add = n500_mabg_mm + _w12
    n500_mabg_div = n500_mabg_add / _w13
    n500_mabg_erf = jax.scipy.special.erf(n500_mabg_div)
    n500_mabg_ep1 = n500_mabg_erf + _w14
    n500_mabg_hf = n500_mabg_add * _w15
    n500_mabg_out = n500_mabg_hf * n500_mabg_ep1
    return jnp.asarray(n500_mabg_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
